DELETE FROM workflow_executions WHERE accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');
DELETE ws FROM workflow_steps ws INNER JOIN workflows w ON ws.workflowId = w.id WHERE w.accountId IN (SELECT id FROM accounts WHERE (LOWER(name) LIKE '%test%' OR LOWER(name) LIKE '%demo%') AND name != 'Apex Systems Test');
